import{_ as e,o as a,c as t,j as r,a as p,a1 as A}from"./chunks/framework.Bp7r_-XI.js";const l=JSON.parse('{"title":"职阶技能","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/职阶技能.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/职阶技能.md"}'),C={name:"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/职阶技能.md"};function s(B,b,D,n,E,o){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"职阶技能",tabindex:"-1"},[p("职阶技能 "),r("a",{class:"header-anchor",href:"#职阶技能","aria-label":'Permalink to "职阶技能"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023")])])],-1),A('<h1 id="职阶技能-1" tabindex="-1">职阶技能 <a class="header-anchor" href="#职阶技能-1" aria-label="Permalink to &quot;职阶技能&quot;">​</a></h1><p>FATE能力组（职阶技能）<br> 描述：出自型月系列世界观，本能力组为该世界观内从者具有的相关能力，在购买后主神会将其赋予给轮回者，使轮回者获得近似的能力。<br> 若无特殊说明，则该能力组中所有技能使用差价升级购买（超过下一等级所需分数的部分将忽略不计）。</p><p>若无特殊说明，则该能力组中所有技能的效果为高等级替换低等级。</p><p>对魔力（E，D，C，B，A，EX）<br> 价格：1000/D+500/C+1000/B+2000/A+4000/S+8000<br> 特殊：该技能不获得自由属性<br> 分类：被动<br> 描述：对魔术的抵抗能力，令魔术效果减弱。<br> 【E级】<br> 无法无效化魔术，只能减少伤害；与魔术的世界完全无关的级别。<br> 【D级】<br> 无效化一工程（Singel Action）魔术。躲避魔力的护身符级别的对魔力；与神代或魔术有所关联，然而对其了解仅限于皮毛（多为近代从者的规格）。<br> 【C级】<br> 无效化魔术咏唱二节以下的魔术。但无法防御大魔法、仪礼咒法等大规模魔术；与神代或魔术有所关联但无论是了解还是抵抗能力都并不著称（多为常规英雄水平）。<br> 【B级】<br> 无效化魔术咏唱三节以下的魔术。大魔法、仪礼咒法等也很难对其造成伤害；与神代或魔术密切相关，并且有一定程度抵抗能力（多为受赐英雄或受人传唱的英雄）。<br> 【A级】<br> 对一定等级以下的魔术全部免疫。实际上，现代的魔术完全无法对其造成伤害，甚至对于一道令咒也有拒绝的权利。<br> 【EX级】<br> 极高的抗魔力，魔术效果对该单位等同于无效，令咒的命令效果也是如此。但是，这只是将魔术的轨迹偏移（躲开），在大范围魔术的攻击下只能保护自身。<br> 效果：<br> E级只为购买者提供1点全能量吸收效果，D-A级会为购买者提供该技能等级-1级的心智类能量效果免疫的能力。（即对方使用基于心智类能量驱动的能力时，购买者可以免疫对方因对应能力获得的加值，防御，伤害，效果等等一切内容。D级可以免疫无支线等级，C级可以免疫D级，以此类推。）</p><p>当处于型月世界观下，该能力可以直接发挥描述中不同等级具有的效果，而不是只有下述效果内提到的内容。</p><p>骑乘（E，D，C，B，A，EX）<br> 价格：1000/D+500/C+1000/B+2000/A+4000/S+8000<br> 分类：被动<br> 描述：骑乘的才能。<br> 【E级】<br> 没有骑马活跃的逸事，只有对不起程度的职阶补正。<br> 【D级】<br> 如果正确的调教、调整的话，就可以万无一失的骑乘。<br> 【C级】<br> 只有骑马的水平超过常人。<br> 【B级】<br> 交通工具上有着超过常人的驾驭能力，但是无法驾驭魔兽、圣兽级别的兽。<br> 【A级】除了幻兽、神兽等级以外的所有的兽、交通工具都能自如地操纵。<br> 【EX级】除了龙和神兽，幻兽都能驾驭外，连宇宙飞船也能驾驭。<br> 效果：<br> E级只为购买者提供3DP器用相关检定上的增强加值，D-EX级则相应提升器用1/2/4/8/16级，但若在购买前器用技能已抵达5/8/11/14/20级，则改为获得2/2/5/11/25点器用相关检定上的增强加值，以及额外获得对应检定上0/1/2/3/5个附加成功。</p><p>此外，该技能在D/C/B级会提供：在驾驭载具时，载具触及距离增加传奇智力*1米/载具获得普通机动性飞行能力/载具获得完美机动性飞行能力。<br> 在A等级时，你驾驶的载具具有A级旅行速度能力，这意味着可以通过十分钟的旅行准备，在具有坐标系的情况，使用曲率或其他类似高速移动手段，在一小时抵达影片世界内的任意一点，这是一个A级空间来源的传送旅行效果。<br> 在EX等级时，你可以驾驭超级宇宙飞船！……当然，驾驭超级宇宙飞船的能力只有在型月世界观下才能生效。</p><p>单独行动（C，B，A，EX）<br> 价格：250/500/1000/D+500<br> 分类：被动<br> 描述：所需魔力减少，即使没有 Master提供魔力也可以继续现界。<br> 效果：<br> 每轮一次，当你使用第一次心智类（通常只能对魔力或者变体魔力类效果生效）能量消耗时，减少1/1/2/2点消耗（C，B，A，EX级）。此外，你在使用消耗对应能量的技艺时，如果是攻击技艺则获得0/1/2点增强加值（C，B，A级），EX级则改为提供1点对应攻击附加成功。</p><p>在型月世界观下，如果你作为从者显界，即使没有御主或御主中断供魔，也可以自由活动一天/两天/一周/即使没有御主也可以自由行动（C，B，A，EX级）。</p><p>气息遮断（D，C，B，A）<br> 价格：D+500/C+1000/B+2000/A+4000<br> 分类：被动<br> 描述：隐蔽气息，适合隐秘行动中使用。D等级的话只有提高隐秘行动适应性的程度，但等级A的话几乎不会被发现。<br> 效果：<br> 根据等级，你获得D，C，B，A级特异本质的反侦测能力。特殊的是，该技能的反侦测效果虽然对于侦测能力生效，但你在D等级时只能选择同时遮蔽：声音、热感应、光学、心灵其中的一种，C级选择另一种，以此类推，在A级时完全遮蔽。<br> 这意味着如果你在D级选择了光学（即隐形），则依旧会暴露在热感应中，行动也会造成声音，也会被心灵感应发现，这不会为你带来额外的好处，只代表没有被遮蔽的部分会被对应本质或来源的侦测能力立刻发现。<br> 此外，若你主动出手进行攻击，则在攻击后会在本轮内失去该能力提供的反侦测效果。</p><p>狂化（D，C，B，A，EX）<br> 价格：500/D+1000/C+1500/B+2500/A+4000<br> 分类：被动<br> 描述：以理性作为交换使得各种属性提升的能力。基本可以令除幸运以外的的能力阶级提升，但夺走大部分理性。<br> 【D级】<br> 可以进行正常的交流，语言会简化。<br> 【C级】<br> 只能听懂言语，也可以做出简短的回应，无法长时间思考，在战斗中则无法交流。<br> 【B级】<br> 只能听懂一部分的指令，而传达到的指令也会根据设定产生些许差错，完全丧失交流能力。<br> 【A级】<br> 无法完全理解语言指令了，必须通过提前指定目标，如同野兽。<br> 【EX级】<br> 疯狂变成具有某些特殊条件的，平时会保持理性、可以进行顺畅的交流，然而，对于某些事物会有着非同寻常的执着，自行设定。<br> 效果：<br> 该技能提供2/4/5/7点（无支线，C，B，A级）力量检定加值，在D/C/B级时额外获得对应检定上的1/1/2个附加成功。<br> C级会使加值扩展到力量和耐力，B级则还包括敏捷。此外，在A级时改为获得9DP全检定加值与1点全检定上的附加成功，此处提到的等级皆为价格等级而不是名称等级。<br> 该技能具有扮演限制，见描述。如果购买者具有-/6/11/16/21点决心与沉着，则无视上述对应D/C/B/A/EX级扮演限制，可以正常保留理性与沟通能力。</p><p>己阵防御（C，B，A）<br> 价格：C+1000/B+2500/A+5000<br> 分类：被动<br> 描述：守护己方或是己方阵营时发挥的实力。能突破防御极限值地削减我方遭到的伤害，但自身并不算在防御对象内。此外，阶级越高，守备范围越广。<br> 效果：<br> 该技能在 C/B/A 级时，对应最大守护范围为：身边5米内的友方目标/身边15米内所有友方目标/身边15+传奇耐力*20米内的所有友方目标。<br> 范围内的目标根据等级依次获得5/8/你的耐力*1点偏斜防御，并且在A级时额外获得2点全伤害吸收效果。</p><p>射击/狙击（E，D，C，B，A，EX）<br> 价格：1000/D+500/C+1000/B+2000/A+4000/S+8000<br> 分类：被动<br> 描述：「火枪手」等一类近现代从者能够获取的特殊技能，对于枪械的应用程度以及使用枪械射击来作为攻击手段的强度。<br> 效果：<br> E级只为购买者提供3DP射击相关检定上的增强加值，D-EX级则相应提升射击1/2/4/8/16级，但若在购买前射击技能已抵达5/8/11/14/20级，则改为获得2/2/5/11/25点射击相关检定上的增强加值，以及额外获得对应检定上0/1/2/3/5个附加成功。</p><p>此外，该技能在D/C/B/A/EX级会提供：枪械基础射程+1倍。（步枪和狙击枪则改为基础射程+30米）。<br> ——<br> 每轮一次，使用枪械攻击时若对结果不满意，则可以进行一次重骰，必须接受第二次结果<br> ——<br> 每轮一次，使用枪械攻击时若对结果不满意，则可以进行一次重骰，取高。<br> ——<br> 每轮一次，使用枪械攻击时可以使成功数增加一半。<br> ——<br> 你的枪械攻击具有【传奇】特性。</p><p>阵地建造（C，B，A）<br> 价格：C+1500/B+2500/A+4000<br> 消耗：6/10/14点任意通用能量<br> 动作：见下<br> 范围：见下<br> 持续：永久<br> 描述：以魔术师的身份，建造对自己有利的阵地。高等级的话则可以构筑超过「工房」的「神殿」。构筑的阵地可以额外具有自己想要拥有的特殊属性，例如降低魔术消耗、提升魔术伤害等效果。<br> 不同等级的阵地其建造所需要耗费的时间与材料肯定不同，而主神简化了这一部分，现在你只需要足够的时间和消耗就可以制造固定的阵地了。<br> 效果：见通用魔法-阵地建造的部分。</p><p>道具制作（E，D，C，B，A）<br> 价格：暂不开放<br> 描述：可以制作带有魔力的器具。<br> 从用于战斗的道具到日用品，能自由自在地造出林林总总的物品。<br> 【E级】<br> 相当于你完全不持有这方面的技能，只不过依靠职阶混到了一点皮毛，总而言之，能够做得出类似于布偶娃娃的东西吧，仅仅能够使用E级的民用级别、随手就能够买到的地摊货材料。<br> 【D级】<br> 算得上是 Caster中的异类了，这种级别的话，能够做得出的都是一些粗制滥造、质量不稳定的成品，甚至只能与现代的流水线产品做比较，能够使用D级的轻工业级别的材料。<br> 【C级】<br> 算是Caster中的及格水平了，但是仍旧十分生疏，做出来的成品也不见得能有多好，更不要说使用高级材料了，这些都是对于C 级而言不可能运用的，仅仅能够运用 C 级的重工业级别的材料。<br> 【B级】<br> 涵盖了 Caster 中的二流到一流末端的从者，曾经担当过魔术方面的助手、与什么样的精灵签订契约而获取的知识、勤勤恳恳获取的宏伟知识，大概就在这一级别，能够娴熟地运用 B 级的军工业级别、世界上最罕见的材料，通过这一等级技能制造出来的道具，甚至能够具有一次性的E级宝具的效果，但是实际上的效果会下降 50%。<br> 【A级】<br> Caster中的佼佼者才能够持有的才能，持有这种等级的道具制作都是那些最一流的Caster，能够完美地运用各种各样的材料，就算是归于A级的神代材料，都不在话下，通过这一技能制造出来的道具，甚至能够具有一次性的D级宝具的效果，但是实际上的效果会下降。<br> 效果：-</p><p>领域外的生命（C，B，A）<br> 价格：C+1000/B+2000/A+4000<br> 描述：磅礴无垠的宇宙中，超乎人类常识之外的存在会在某些时刻造访人类的世界，然而这些存在对人类却毫无兴趣——如果不是怀有恶意的话。<br> 效果：<br> 该技能在提供同价格等级的心灵、环境免疫效果。此外，根据等级获得对应的特殊效果。<br> 在C级时，购买者获得免疫附身来源效果，最高不能超过技能等级-1级。<br> 在B级时，购买者获得免疫即死来源效果，最高不能超过技能等级+1级。<br> 在A级时，购买者获得免疫时空，命运来源的效果，最高不能超过技能相同等级。<br> 【特殊的是，该能力可以逐级购买，以获得多项免疫能力，让你的存在本质更接近超乎常识的存在。】</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',19)])])}const i=e(C,[["render",s]]);export{l as __pageData,i as default};
